#include <stdio.h>
#include <string.h>

char s1[1001], s2[1001];
int dp[1001][1001];

void printSupersequence(int i, int j) {
    if (i == 0 && j == 0) return;
    if (i > 0 && j > 0 && s1[i-1] == s2[j-1]) {
        printSupersequence(i-1, j-1);
        printf("%c", s1[i-1]);
    } else if (j > 0 && (i == 0 || dp[i][j] == dp[i][j-1])) {
        printSupersequence(i, j-1);
        printf("%c", s2[j-1]);
    } else {
        printSupersequence(i-1, j);
        printf("%c", s1[i-1]);
    }
}

int main() {
    scanf("%s %s", s1, s2);
    int n = strlen(s1), m = strlen(s2);
    for (int i = 0; i <= n; i++) {
        for (int j = 0; j <= m; j++) {
            if (i == 0) dp[i][j] = j;
            else if (j == 0) dp[i][j] = i;
            else if (s1[i-1] == s2[j-1]) dp[i][j] = 1 + dp[i-1][j-1];
            else dp[i][j] = 1 + (dp[i-1][j] < dp[i][j-1] ? dp[i-1][j] : dp[i][j-1]);
        }
    }
    printSupersequence(n, m);
    return 0;
}

