    shortestSupersequence(s1, s2) {

        // Get lengths of both strings
        const n = s1.length;
        const m = s2.length;

        // Create a 2D DP array filled with 0s
        const dp = Array.from({ length: n + 1 }, () => Array(m + 1).fill(0));

        // Fill the DP table using bottom-up approach
        for (let i = 1; i <= n; i++) {
            for (let j = 1; j <= m; j++) {

                // If characters match, take diagonal + 1
                if (s1[i - 1] === s2[j - 1]) {
                    dp[i][j] = 1 + dp[i - 1][j - 1];
                }

                // Otherwise, take max from top or left
                else {
                    dp[i][j] = 1 + (dp[i - 1][j] > dp[i][j - 1] ? dp[i - 1][j] : dp[i][j - 1]);
                }
            }
        }

        // Initialize result string builder
        let result = [];

        // Start from bottom-right of DP table
        let i = n, j = m;

        // Traverse in reverse to build supersequence
        while (i > 0 && j > 0) {

            // If characters match, add to result
            if (s1[i - 1] === s2[j - 1]) {
                result.push(s1[i - 1]);
                i--;
                j--;
            }

            // Move in direction of larger value
            else if (dp[i - 1][j] > dp[i][j - 1]) {
                result.push(s1[i - 1]);
                i--;
            } else {
                result.push(s2[j - 1]);
                j--;
            }
        }

        // Add remaining characters from s1
        while (i > 0) {
            result.push(s1[i - 1]);
            i--;
        }

        // Add remaining characters from s2
        while (j > 0) {
            result.push(s2[j - 1]);
            j--;
        }

        // Reverse the result to correct order
        result.reverse();

        // Return final string
        return result.join('');
    }
}

